#pragma once\n#include <list>\n#include <unordered_map>\n#include <mutex>\n\nclass LRUCache {\npublic:\n    explicit LRUCache(int capacity);\n    int get(int key);\n    void put(int key, int value);\n\nprivate:\n    struct CacheNode {\n        int key;\n        int value;\n        CacheNode(int k, int v) : key(k), value(v) {}\n    };\n\n    std::list<CacheNode> cacheList;\n    std::unordered_map<int, std::list<CacheNode>::iterator> cacheMap;\n    int capacity;\n    std::mutex mtx;\n};\n